code.snippet:
struct Counter { public int Value; }

var list = new List<Counter>
{
    new Counter { Value = 0 },
    new Counter { Value = 0 }
};

var result = list
    // First Select: IEnumerator.Current gives a COPY (Value=0), lambda
    // increments its local copy to 1, returns that copy.
    .Select(c => { c.Value++; return c; })
    // Second Select: receives the copy (Value=1), increments to 2, returns it.
    .Select(c => { c.Value++; return c; })
    .ToList();

Console.WriteLine(list[0].Value);   // 0 — original list never touched
Console.WriteLine(result[0].Value); // 2 — two increments applied to pipeline copies
